class HarmonicOscillator(nn.Module):
    """
    Differentiable Harmonic Additive Oscillator matching Vital's "Basic Shapes".
    Uses 1024 complex kernels for zero-ripple reconstruction.
    """
    def __init__(self, n_harmonics: int = 1024, sample_rate: int = 44100):
        super().__init__()
        self.n_harmonics = n_harmonics
        self.sample_rate = sample_rate
        
        # Register kernels as buffers
        self.register_buffer("mags", torch.zeros(7, n_harmonics))
        self.register_buffer("phases", torch.zeros(7, n_harmonics))
        
        sorted_pos = [0, 32, 64, 96, 128, 192, 224]
        for i, pos in enumerate(sorted_pos):
            m, p = VITAL_KERNELS[pos]
            self.mags[i] = torch.tensor(m[:n_harmonics])
            self.phases[i] = torch.tensor(p[:n_harmonics])

    def forward(self, 
                f0: torch.Tensor, 
                level: torch.Tensor, 
                wavetable_pos: torch.Tensor, 
                global_phase_offset: float = 0.0,
                temp: float = 0.1) -> torch.Tensor:
        batch_size, n_samples, _ = f0.shape
        device = f0.device
        
        # 1. Categorical Gating
        shape_pos = torch.tensor([0, 32, 64, 96, 128, 192, 224], device=device).float() / 255.0
        dist = -torch.abs(wavetable_pos.view(-1, 1, 1) - shape_pos.view(1, 1, -1))
        probs = F.softmax(dist / temp, dim=-1)
        
        # 2. Kernel Summation
        h_mags = torch.matmul(probs, self.mags)
        h_phases = torch.matmul(probs, self.phases)
        
        # 3. Phase Calculation
        harms = torch.arange(1, self.n_harmonics + 1, device=device).float()
        omega = 2 * np.pi * f0 / self.sample_rate
        phi_f0 = torch.cumsum(omega, dim=1) - omega + global_phase_offset
        phases = phi_f0 * harms + h_phases
        
        # 4. Anti-Aliasing
        nyquist = self.sample_rate / 2
        f_harmonics = f0 * harms
        mask = (f_harmonics < nyquist).float()
        
        # 5. Synthesis (Cosine-based)
        audio = torch.sum(h_mags * mask * torch.cos(phases), dim=-1)
        
        return audio * level

class DifferentiableADSR(nn.Module):
    def __init__(self, sample_rate: int = 44100):
        super().__init__()
        self.sample_rate = sample_rate

    def forward(self, 
                duration_samples: int, 
                attack: torch.Tensor, 
                decay: torch.Tensor, 
                sustain: torch.Tensor, 
                release: torch.Tensor,
                gate: torch.Tensor) -> torch.Tensor:
        batch_size = attack.shape[0]
        device = attack.device
        t_a = 0.001 + attack * 7.999
        t_d = 0.001 + decay * 7.999
        t_r = 0.001 + release * 7.999
        t = torch.linspace(0, duration_samples / self.sample_rate, duration_samples, device=device).unsqueeze(0)
        env_a = torch.clamp(t / (t_a + 1e-8), 0, 1)
        tau_d = t_d / 3.0
        env_d = sustain + (1.0 - sustain) * torch.exp(-(t - t_a) / (tau_d + 1e-8))
        env_d = torch.maximum(torch.minimum(env_d, torch.ones_like(env_d)), sustain)
        env = torch.where(t < t_a, env_a, env_d)
        gate_off_mask = (gate == 0).float()
        off_idx = torch.argmax(gate_off_mask, dim=1, keepdim=True)
        t_off = off_idx.float() / self.sample_rate
        tau_r = t_r / 3.0
        env_r = torch.exp(-(t - t_off) / (tau_r + 1e-8))
        env = torch.where(t < t_off, env, env * env_r)
        return env * gate

class DifferentiableFilterSVF(nn.Module):
    def __init__(self, sample_rate: int = 44100):
        super().__init__()
        self.sample_rate = sample_rate

    def forward(self, x: torch.Tensor, cutoff: torch.Tensor, resonance: torch.Tensor) -> torch.Tensor:
        batch_size, n_samples = x.shape
        device = x.device
        cutoff_hz = 20.0 * (1000.0 ** cutoff)
        k = 2.0 - 1.95 * resonance
        g = torch.tan(np.pi * cutoff_hz / self.sample_rate)
        s1 = torch.zeros(batch_size, device=device)
        s2 = torch.zeros(batch_size, device=device)
        out = torch.zeros_like(x)
        g = g.expand(batch_size, n_samples)
        k = k.expand(batch_size, n_samples)
        for i in range(n_samples):
            v0 = x[:, i]
            v3 = v0 - s2
            v1 = (g[:, i] * v3 + s1) / (1 + g[:, i] * (g[:, i] + k[:, i]))
            v2 = g[:, i] * v1 + s2
            s1 = 2 * v1 - s1
            s2 = 2 * v2 - s2
            out[:, i] = v2 
        return out

class VitalProxy(nn.Module):
    def __init__(self, n_harmonics: int = 1024, sample_rate: int = 44100):
        super().__init__()
        self.osc = HarmonicOscillator(n_harmonics, sample_rate)
        self.adsr = DifferentiableADSR(sample_rate)
        self.filter = DifferentiableFilterSVF(sample_rate)
        self.sample_rate = sample_rate

    def forward(self, 
                f0: torch.Tensor, 
                oscillator_1_level: torch.Tensor,
                oscillator_1_wave_frame: torch.Tensor,
                filter_1_cutoff: torch.Tensor,
                filter_1_resonance: torch.Tensor,
                envelope_1_attack: torch.Tensor,
                envelope_1_decay: torch.Tensor,
                envelope_1_sustain: torch.Tensor,
                envelope_1_release: torch.Tensor,
                gate: torch.Tensor,
                temp: float = 0.1,
                phase_offset: float = 0.0,
                input_audio: Optional[torch.Tensor] = None,
                return_raw: bool = False) -> torch.Tensor:
        batch_size = f0.shape[0]
        n_samples = gate.shape[1]
        if f0.dim() == 2:
            f0 = f0.unsqueeze(1).repeat(1, n_samples, 1)
        elif f0.dim() == 1:
            f0 = f0.unsqueeze(1).unsqueeze(1).repeat(1, n_samples, 1)
        raw_audio = self.osc(f0, oscillator_1_level, oscillator_1_wave_frame, global_phase_offset=phase_offset, temp=temp)
        if return_raw:
            return raw_audio
        env = self.adsr(n_samples, envelope_1_attack, envelope_1_decay, envelope_1_sustain, envelope_1_release, gate)
        env_audio = raw_audio * env
        filtered_audio = self.filter(env_audio, filter_1_cutoff, filter_1_resonance)
        return filtered_audio
